/**
 * InventoryPanel — Full equipment doll + inventory grid + stats panel.
 * DOM overlay (position: fixed) over the PixiJS canvas. Toggled with `I`.
 *
 * Layout:
 *   [Equipment doll] | [Inventory grid] | [Character stats]
 *   Party tabs at top to switch characters.
 *
 * @module InventoryPanel
 */

import { UIPanel } from './UIPanel.js';
import DebugLog from '../debug/DebugLog.js';
import ItemSystem from '../systems/ItemSystem.js';
import CharacterSystem from '../systems/CharacterSystem.js';
import WorldState from '../world/WorldState.js';

// ─── Styles ───────────────────────────────────────────────────────────────────

const STYLE_ID = 'spellroads-inventory-style';

function injectStyles() {
  if (document.getElementById(STYLE_ID)) return;
  const style = document.createElement('style');
  style.id = STYLE_ID;
  style.textContent = `
    /* ══════════════════════════════════════════════════════════════
       InventoryPanel — Spellroads
       ══════════════════════════════════════════════════════════════ */

    #panel-inventory {
      position: fixed;
      inset: 0;
      z-index: 210;
      display: none;
      background: rgba(8, 6, 4, 0.97);
      flex-direction: column;
      pointer-events: all;
      overflow: hidden;
      font-family: 'Georgia', 'Times New Roman', serif;
    }
    #panel-inventory.visible { display: flex; }

    /* ── Header ──────────────────────────────────────────────────── */
    .inv-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: clamp(8px,1.5vh,14px) clamp(12px,2vw,24px);
      background: rgba(0,0,0,0.5);
      border-bottom: 1px solid rgba(200,160,32,0.25);
      flex-shrink: 0;
      gap: 12px;
    }
    .inv-title {
      font-size: clamp(0.9rem,1.8vw,1.2rem);
      font-weight: 700;
      color: #c8a020;
      letter-spacing: 0.08em;
      text-transform: uppercase;
    }
    .inv-gold {
      font-size: clamp(0.75rem,1.3vw,0.9rem);
      color: #d4b870;
      font-weight: 600;
    }
    .inv-close {
      background: none;
      border: 1px solid rgba(200,160,32,0.3);
      color: #a09070;
      cursor: pointer;
      width: 36px; height: 36px;
      min-width: 36px; min-height: 36px;
      border-radius: 4px;
      font-size: 1.1rem;
      display: flex; align-items: center; justify-content: center;
      transition: color 0.15s, border-color 0.15s;
    }
    .inv-close:hover { color: #c8a020; border-color: #c8a020; }

    /* ── Party Tabs ──────────────────────────────────────────────── */
    .inv-tabs {
      display: flex;
      gap: 4px;
      padding: 8px clamp(12px,2vw,24px) 0;
      background: rgba(0,0,0,0.3);
      flex-shrink: 0;
      overflow-x: auto;
    }
    .inv-tab {
      padding: 6px 14px;
      background: rgba(255,255,255,0.04);
      border: 1px solid rgba(200,160,32,0.15);
      border-bottom: none;
      border-radius: 4px 4px 0 0;
      color: #a09070;
      font-size: clamp(0.65rem,1.1vw,0.78rem);
      font-weight: 600;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      cursor: pointer;
      min-height: 44px;
      min-width: 60px;
      display: flex; align-items: center; justify-content: center;
      gap: 6px;
      white-space: nowrap;
      transition: background 0.12s, color 0.12s;
    }
    .inv-tab:hover { background: rgba(200,160,32,0.1); color: #c8d0a0; }
    .inv-tab.active {
      background: rgba(8,6,4,0.9);
      border-color: rgba(200,160,32,0.35);
      color: #c8a020;
    }

    /* ── Body ─────────────────────────────────────────────────────── */
    .inv-body {
      flex: 1;
      display: grid;
      grid-template-columns: 220px 1fr 220px;
      gap: 0;
      overflow: hidden;
      min-height: 0;
    }

    /* ── Section shared ──────────────────────────────────────────── */
    .inv-section {
      padding: clamp(10px,1.5vw,16px);
      overflow-y: auto;
      border-right: 1px solid rgba(200,160,32,0.12);
    }
    .inv-section:last-child { border-right: none; }
    .inv-section-title {
      font-size: clamp(0.62rem,1vw,0.72rem);
      color: #c8a020;
      text-transform: uppercase;
      letter-spacing: 0.1em;
      margin-bottom: 10px;
      padding-bottom: 6px;
      border-bottom: 1px solid rgba(200,160,32,0.15);
    }

    /* ── Equipment doll ──────────────────────────────────────────── */
    .inv-equip-doll {
      display: grid;
      grid-template-areas:
        ". helmet ."
        "ring1 chest ring2"
        ". gloves ."
        "belt legs amulet"
        "weapon boots offhand"
        ". quiver .";
      grid-template-columns: 1fr 1fr 1fr;
      gap: 6px;
    }
    .inv-slot {
      position: relative;
      width: 100%;
      aspect-ratio: 1;
      background: rgba(255,255,255,0.03);
      border: 1px solid rgba(200,160,32,0.18);
      border-radius: 4px;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-direction: column;
      gap: 2px;
      transition: border-color 0.12s, background 0.12s;
      overflow: hidden;
      min-height: 44px;
    }
    .inv-slot:hover { border-color: rgba(200,160,32,0.5); background: rgba(200,160,32,0.05); }
    .inv-slot.has-item { border-color: rgba(200,160,32,0.35); }
    .inv-slot.req-warn { border-color: rgba(200,50,30,0.6); }
    .inv-slot-label {
      font-size: 0.52rem;
      color: rgba(160,144,112,0.6);
      text-transform: uppercase;
      letter-spacing: 0.06em;
      line-height: 1;
    }
    .inv-slot-icon { font-size: 1.1rem; line-height: 1; }
    .inv-slot-name {
      font-size: 0.5rem;
      color: #c8d0a0;
      text-align: center;
      padding: 0 2px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
      width: 100%;
    }
    .inv-slot .req-badge {
      position: absolute;
      top: 2px; right: 2px;
      width: 10px; height: 10px;
      background: #c83020;
      border-radius: 50%;
    }
    /* slot grid areas */
    .inv-slot[data-slot="helmet"]  { grid-area: helmet; }
    .inv-slot[data-slot="armor"]   { grid-area: chest; }
    .inv-slot[data-slot="legs"]    { grid-area: legs; }
    .inv-slot[data-slot="boots"]   { grid-area: boots; }
    .inv-slot[data-slot="gloves"]  { grid-area: gloves; }
    .inv-slot[data-slot="ring1"]   { grid-area: ring1; }
    .inv-slot[data-slot="ring2"]   { grid-area: ring2; }
    .inv-slot[data-slot="amulet"]  { grid-area: amulet; }
    .inv-slot[data-slot="belt"]    { grid-area: belt; }
    .inv-slot[data-slot="weapon"]  { grid-area: weapon; }
    .inv-slot[data-slot="offhand"] { grid-area: offhand; }
    .inv-slot[data-slot="quiver"]  { grid-area: quiver; }

    /* ── Inventory grid ──────────────────────────────────────────── */
    .inv-center {
      display: flex;
      flex-direction: column;
      gap: 10px;
      overflow: hidden;
    }
    .inv-grid-wrap {
      flex: 1;
      overflow-y: auto;
      padding: clamp(10px,1.5vw,16px);
    }
    .inv-grid {
      display: grid;
      grid-template-columns: repeat(6, 48px);
      gap: 4px;
    }
    .inv-cell {
      width: 48px; height: 48px;
      background: rgba(255,255,255,0.025);
      border: 1px solid rgba(200,160,32,0.12);
      border-radius: 3px;
      position: relative;
      cursor: pointer;
      display: flex; align-items: center; justify-content: center;
      overflow: hidden;
      transition: border-color 0.12s;
      user-select: none;
    }
    .inv-cell:empty { cursor: default; }
    .inv-cell.has-item { border-color: rgba(200,160,32,0.3); }
    .inv-cell.has-item:hover { border-color: rgba(200,160,32,0.6); background: rgba(200,160,32,0.06); }
    .inv-cell.selected { border-color: #c8a020; background: rgba(200,160,32,0.12); }
    .inv-cell.drag-over { border-color: #c8c030; background: rgba(200,192,48,0.1); }
    .inv-cell-icon { font-size: 1.4rem; }
    .inv-cell-qty {
      position: absolute;
      bottom: 1px; right: 3px;
      font-size: 0.55rem;
      color: #c8d0a0;
      font-weight: bold;
      line-height: 1;
    }
    .inv-cell-rarity-bar {
      position: absolute;
      bottom: 0; left: 0; right: 0;
      height: 2px;
    }

    /* ── Weight bar ──────────────────────────────────────────────── */
    .inv-weight {
      padding: 8px clamp(10px,1.5vw,16px);
      background: rgba(0,0,0,0.3);
      border-top: 1px solid rgba(200,160,32,0.12);
      flex-shrink: 0;
      display: flex;
      align-items: center;
      gap: 8px;
      font-size: clamp(0.6rem,1vw,0.72rem);
      color: #a09070;
    }
    .inv-weight-label { flex-shrink: 0; }
    .inv-weight-bar {
      flex: 1;
      height: 6px;
      background: rgba(255,255,255,0.06);
      border-radius: 3px;
      overflow: hidden;
    }
    .inv-weight-fill {
      height: 100%;
      background: #4a7a2a;
      border-radius: 3px;
      transition: width 0.2s, background 0.2s;
    }
    .inv-weight-fill.overweight { background: #c83020; }
    .inv-weight-value { flex-shrink: 0; min-width: 70px; text-align: right; }

    /* ── Stats panel ─────────────────────────────────────────────── */
    .inv-stats-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 4px 8px;
      font-size: clamp(0.6rem,1vw,0.7rem);
    }
    .inv-stat-row {
      display: flex;
      justify-content: space-between;
      gap: 4px;
      padding: 2px 0;
      border-bottom: 1px solid rgba(200,160,32,0.07);
    }
    .inv-stat-label { color: #a09070; }
    .inv-stat-value { color: #e8d5b0; font-weight: 600; }
    .inv-stat-value.good  { color: #40a060; }
    .inv-stat-value.warn  { color: #e07820; }
    .inv-stat-value.bad   { color: #c83020; }

    /* ── Tooltip ─────────────────────────────────────────────────── */
    #inv-tooltip {
      position: fixed;
      z-index: 9990;
      background: rgba(8,6,4,0.97);
      border: 1px solid rgba(200,160,32,0.3);
      border-radius: 5px;
      padding: 10px 12px;
      min-width: 200px;
      max-width: 280px;
      pointer-events: none;
      display: none;
      box-shadow: 0 4px 18px rgba(0,0,0,0.7);
    }
    #inv-tooltip.visible { display: block; }
    .tt-name {
      font-size: clamp(0.75rem,1.2vw,0.9rem);
      font-weight: 700;
      margin-bottom: 4px;
    }
    .tt-type {
      font-size: 0.6rem;
      color: #706050;
      text-transform: uppercase;
      letter-spacing: 0.06em;
      margin-bottom: 8px;
    }
    .tt-stat { font-size: 0.68rem; color: #c8d0a0; margin-bottom: 2px; }
    .tt-affix {
      font-size: 0.65rem;
      color: #7090c0;
      margin-bottom: 2px;
      font-style: italic;
    }
    .tt-req {
      font-size: 0.62rem;
      color: #c83020;
      margin-top: 4px;
    }
    .tt-desc {
      font-size: 0.62rem;
      color: #706050;
      margin-top: 6px;
      padding-top: 6px;
      border-top: 1px solid rgba(200,160,32,0.1);
    }
    .tt-delta { font-size: 0.65rem; margin-top: 6px; padding-top: 6px; border-top: 1px solid rgba(200,160,32,0.1); }
    .tt-delta-row { display: flex; justify-content: space-between; gap: 8px; }
    .tt-delta-plus  { color: #40a060; }
    .tt-delta-minus { color: #c83020; }
    .tt-unid { color: #a09070; font-style: italic; }
    .tt-action {
      font-size: 0.58rem;
      color: #706050;
      margin-top: 6px;
      text-align: center;
    }

    /* ── Sell area ───────────────────────────────────────────────── */
    .inv-sell-area {
      padding: 6px 10px;
      text-align: center;
      font-size: clamp(0.6rem,1vw,0.7rem);
      color: #706050;
      border-top: 1px solid rgba(200,160,32,0.1);
      cursor: pointer;
      transition: color 0.12s;
    }
    .inv-sell-area:hover { color: #c8a020; }
    .inv-sell-area.drag-over { background: rgba(200,160,32,0.08); color: #c8a020; }

    /* ── Mobile layout (portrait) ────────────────────────────────── */
    @media (max-width: 767px) and (orientation: portrait) {
      .inv-body {
        grid-template-columns: 1fr;
        grid-template-rows: auto 1fr auto;
      }
      .inv-section { border-right: none; border-bottom: 1px solid rgba(200,160,32,0.12); }
      .inv-section:last-child { border-bottom: none; }
      .inv-equip-doll { grid-template-columns: repeat(6,1fr); grid-template-areas: unset; }
      .inv-slot[data-slot] { grid-area: unset; }
      .inv-grid { grid-template-columns: repeat(4,48px); }
    }

    /* ── Mobile landscape ─────────────────────────────────────────── */
    @media (max-width: 1023px) and (orientation: landscape) {
      .inv-body { grid-template-columns: 160px 1fr 160px; }
    }
  `;
  document.head.appendChild(style);
}

// ─── Slot config ──────────────────────────────────────────────────────────────

const SLOT_CONFIG = [
  { id: 'helmet',  label: 'Helm',    icon: '\u26CF' },
  { id: 'armor',   label: 'Chest',   icon: '\uD83E\uDDE5' },
  { id: 'gloves',  label: 'Gloves',  icon: '\uD83E\uDDE4' },
  { id: 'legs',    label: 'Legs',    icon: '\uD83D\uDC56' },
  { id: 'boots',   label: 'Boots',   icon: '\uD83D\uDC62' },
  { id: 'belt',    label: 'Belt',    icon: '\u26AA' },
  { id: 'ring1',   label: 'Ring',    icon: '\uD83D\uDC8D' },
  { id: 'ring2',   label: 'Ring',    icon: '\uD83D\uDC8D' },
  { id: 'amulet',  label: 'Amulet',  icon: '\u2763' },
  { id: 'weapon',  label: 'Weapon',  icon: '\u2694' },
  { id: 'offhand', label: 'Offhand', icon: '\uD83D\uDEE1' },
  { id: 'quiver',  label: 'Quiver',  icon: '\uD83C\uDFF9' },
];

const SLOT_ICONS = Object.fromEntries(SLOT_CONFIG.map(s => [s.id, s.icon]));

// Map item subtype → equipment slot for ring2 fallback
function getEquipSlot(base) {
  if (!base.slot) return null;
  return base.slot;
}

// ─── InventoryPanel ───────────────────────────────────────────────────────────

export default class InventoryPanel extends UIPanel {
  constructor() {
    injectStyles();
    super('panel-inventory', { trapFocus: false, zLayer: 'panel' });

    /** @type {object|null} Currently displayed character */
    this._char = null;

    /** @type {object[]} All characters accessible in this panel (P1's party) */
    this._partyChars = [];

    /** @type {object|null} Currently dragged item instance */
    this._dragItem = null;

    /** @type {string|null} Source of drag ('inventory'|slot id) */
    this._dragSource = null;

    /** @type {object|null} Pending identify target */
    this._identifyTarget = null;

    /** @type {boolean} Waiting for identify target selection */
    this._pendingIdentify = false;

    // Tooltip element shared across panel
    this._tooltip = null;
    this._buildTooltip();

    this._setupDebugHooks();
  }

  // ─── DOM build ───────────────────────────────────────────────────────────

  _buildHTML() {
    return `
      <div class="inv-header">
        <span class="inv-title">Inventory</span>
        <span class="inv-gold" id="inv-gold-display">Gold: 0</span>
        <button class="inv-close" id="inv-close-btn" tabindex="0" aria-label="Close inventory">×</button>
      </div>
      <div class="inv-tabs" id="inv-tabs" role="tablist"></div>
      <div class="inv-body">
        <div class="inv-section" id="inv-equip-section">
          <div class="inv-section-title">Equipment</div>
          <div class="inv-equip-doll" id="inv-equip-doll"></div>
        </div>
        <div class="inv-center inv-section" id="inv-center-section">
          <div style="padding:clamp(10px,1.5vw,16px) clamp(10px,1.5vw,16px) 0">
            <div class="inv-section-title">Inventory</div>
          </div>
          <div class="inv-grid-wrap">
            <div class="inv-grid" id="inv-grid"></div>
          </div>
          <div class="inv-sell-area" id="inv-sell-area">Drop here to sell</div>
          <div class="inv-weight" id="inv-weight">
            <span class="inv-weight-label">Weight:</span>
            <div class="inv-weight-bar"><div class="inv-weight-fill" id="inv-weight-fill" style="width:0%"></div></div>
            <span class="inv-weight-value" id="inv-weight-value">0 / 0</span>
          </div>
        </div>
        <div class="inv-section" id="inv-stats-section">
          <div class="inv-section-title">Character Stats</div>
          <div id="inv-stats-content"></div>
        </div>
      </div>
    `;
  }

  // ─── Tooltip ─────────────────────────────────────────────────────────────

  _buildTooltip() {
    if (document.getElementById('inv-tooltip')) {
      this._tooltip = document.getElementById('inv-tooltip');
      return;
    }
    const tt = document.createElement('div');
    tt.id = 'inv-tooltip';
    document.body.appendChild(tt);
    this._tooltip = tt;
  }

  // ─── UIPanel overrides ───────────────────────────────────────────────────

  show(charId = null) {
    // Collect all P1 party characters from CharacterSystem
    this._partyChars = this._getPartyChars();

    // Pick requested character or first in party
    this._char = charId
      ? CharacterSystem.getById(charId) ?? this._partyChars[0] ?? null
      : this._partyChars[0] ?? null;

    if (!this._char && this._partyChars.length === 0) {
      DebugLog.warn('[ui] InventoryPanel: no characters found, creating test character');
      this._char = this._createTestCharacter();
    }

    super.show(charId);
    this._bindPanelEvents();
    this._renderAll();
  }

  hide() {
    this._hideTooltip();
    super.hide();
  }

  updateContent(charId) {
    if (!this._char) return;
    this._renderAll();
  }

  // ─── Party character resolution ──────────────────────────────────────────

  _getPartyChars() {
    // window.__partyState is set by WorldMapScene / PartyBuilderScene
    const partyState = window.__partyState;
    if (partyState?.characters && partyState.characters.length > 0) {
      return partyState.characters.map(c =>
        typeof c === 'string' ? CharacterSystem.getById(c) : c
      ).filter(Boolean);
    }

    // Fallback: all characters in CharacterSystem that are heroes
    const all = CharacterSystem.getAll().filter(c => c.isHero);
    if (all.length > 0) return all;

    // Last fallback: all characters
    return CharacterSystem.getAll().slice(0, 4);
  }

  _createTestCharacter() {
    // Create a minimal test character for dev/testing contexts
    const char = CharacterSystem.createHero({
      name: 'Test Hero',
      raceId: 'human',
      background: { childhood: 'farmer', adult: 'soldier' },
      skillTrees: ['combat'],
    });
    // Give some starting items
    ItemSystem.init();
    const gear = ItemSystem.createStartingGear({ adult: 'soldier' });
    char.inventory = gear;
    this._partyChars = [char];
    return char;
  }

  // ─── Bind events ─────────────────────────────────────────────────────────

  _bindPanelEvents() {
    // Close button
    const closeBtn = this.el.querySelector('#inv-close-btn');
    if (closeBtn && !closeBtn._invBound) {
      closeBtn.addEventListener('click', () => this.hide());
      closeBtn._invBound = true;
    }
  }

  // ─── Full render ──────────────────────────────────────────────────────────

  _renderAll() {
    if (!this._char) return;
    this._renderGold();
    this._renderTabs();
    this._renderEquipDoll();
    this._renderInventoryGrid();
    this._renderStats();
    this._renderWeight();
  }

  // ─── Gold display ─────────────────────────────────────────────────────────

  _renderGold() {
    const el = this.el.querySelector('#inv-gold-display');
    if (el) el.textContent = `Gold: ${WorldState.partyGold ?? 0}`;
  }

  // ─── Tabs ─────────────────────────────────────────────────────────────────

  _renderTabs() {
    const tabsEl = this.el.querySelector('#inv-tabs');
    if (!tabsEl) return;
    tabsEl.innerHTML = '';

    for (const char of this._partyChars) {
      const tab = document.createElement('button');
      tab.className = 'inv-tab' + (char === this._char ? ' active' : '');
      tab.tabIndex = 0;
      tab.setAttribute('role', 'tab');
      tab.setAttribute('aria-selected', char === this._char ? 'true' : 'false');
      tab.textContent = char.name;
      tab.addEventListener('click', () => {
        this._char = char;
        this._renderAll();
      });
      tabsEl.appendChild(tab);
    }
  }

  // ─── Equipment doll ───────────────────────────────────────────────────────

  _renderEquipDoll() {
    const doll = this.el.querySelector('#inv-equip-doll');
    if (!doll) return;
    doll.innerHTML = '';

    for (const slotCfg of SLOT_CONFIG) {
      const slot = document.createElement('div');
      slot.className = 'inv-slot';
      slot.dataset.slot = slotCfg.id;
      slot.tabIndex = 0;
      slot.setAttribute('aria-label', slotCfg.label);

      const equippedItem = this._char.equipment?.[slotCfg.id] ?? null;

      if (equippedItem) {
        slot.classList.add('has-item');

        // Check requirements warning
        const { canEquip, warnings } = ItemSystem.canEquip(this._char, equippedItem);
        if (warnings.length > 0) {
          slot.classList.add('req-warn');
          const badge = document.createElement('div');
          badge.className = 'req-badge';
          badge.title = warnings.join('\n');
          slot.appendChild(badge);
        }

        const rarityColor = ItemSystem.getRarityColor(equippedItem.rarity);
        const iconEl = document.createElement('div');
        iconEl.className = 'inv-slot-icon';
        iconEl.textContent = SLOT_ICONS[slotCfg.id] ?? '?';
        iconEl.style.filter = `drop-shadow(0 0 3px ${rarityColor}80)`;

        const nameEl = document.createElement('div');
        nameEl.className = 'inv-slot-name';
        nameEl.style.color = rarityColor;
        nameEl.textContent = equippedItem.identified
          ? this._shortName(ItemSystem.getItemName(equippedItem))
          : '???';

        slot.appendChild(iconEl);
        slot.appendChild(nameEl);

        // Hover tooltip
        slot.addEventListener('mouseenter', (e) => this._showTooltip(equippedItem, e, slotCfg.id));
        slot.addEventListener('mouseleave', () => this._hideTooltip());
        slot.addEventListener('mousemove', (e) => this._moveTooltip(e));

        // Right-click / shift-click to unequip
        slot.addEventListener('contextmenu', (e) => {
          e.preventDefault();
          this._unequipItem(slotCfg.id);
        });
        slot.addEventListener('click', (e) => {
          if (e.shiftKey) {
            this._unequipItem(slotCfg.id);
          }
        });

        // Drag source from slot
        slot.draggable = true;
        slot.addEventListener('dragstart', (e) => this._onDragStart(e, equippedItem, slotCfg.id));
        slot.addEventListener('dragend', () => this._onDragEnd());
      } else {
        const labelEl = document.createElement('div');
        labelEl.className = 'inv-slot-label';
        labelEl.textContent = slotCfg.label;
        slot.appendChild(labelEl);
      }

      // Drop target on slot
      slot.addEventListener('dragover', (e) => { e.preventDefault(); slot.classList.add('drag-over'); });
      slot.addEventListener('dragleave', () => slot.classList.remove('drag-over'));
      slot.addEventListener('drop', (e) => {
        e.preventDefault();
        slot.classList.remove('drag-over');
        this._onDropToSlot(slotCfg.id);
      });

      doll.appendChild(slot);
    }
  }

  // ─── Inventory grid ───────────────────────────────────────────────────────

  _renderInventoryGrid() {
    const grid = this.el.querySelector('#inv-grid');
    if (!grid) return;
    grid.innerHTML = '';

    const inventory = this._char.inventory ?? [];
    const MIN_CELLS = 24; // 6 cols × 4 rows minimum
    const cellCount = Math.max(MIN_CELLS, Math.ceil((inventory.length + 4) / 6) * 6);

    for (let i = 0; i < cellCount; i++) {
      const cell = document.createElement('div');
      cell.className = 'inv-cell';
      cell.dataset.index = i;

      const item = inventory[i];
      if (item) {
        cell.classList.add('has-item');

        const rarityColor = ItemSystem.getRarityColor(item.rarity);

        const iconEl = document.createElement('div');
        iconEl.className = 'inv-cell-icon';
        iconEl.textContent = this._getItemIcon(item);

        const bar = document.createElement('div');
        bar.className = 'inv-cell-rarity-bar';
        bar.style.background = rarityColor;

        cell.appendChild(iconEl);
        cell.appendChild(bar);

        if (item.quantity > 1) {
          const qty = document.createElement('div');
          qty.className = 'inv-cell-qty';
          qty.textContent = item.quantity;
          cell.appendChild(qty);
        }

        // Hover tooltip
        cell.addEventListener('mouseenter', (e) => this._showTooltip(item, e, null));
        cell.addEventListener('mouseleave', () => this._hideTooltip());
        cell.addEventListener('mousemove', (e) => this._moveTooltip(e));

        // Click to equip / use
        cell.addEventListener('click', (e) => {
          if (this._pendingIdentify) {
            this._resolveIdentify(item);
            return;
          }
          this._onCellClick(item, i, e);
        });

        // Right-click / shift-click to use consumable
        cell.addEventListener('contextmenu', (e) => {
          e.preventDefault();
          this._onCellRightClick(item, i);
        });

        // Drag
        cell.draggable = true;
        cell.addEventListener('dragstart', (e) => this._onDragStart(e, item, 'inventory'));
        cell.addEventListener('dragend', () => this._onDragEnd());
      }

      // Drop target
      cell.addEventListener('dragover', (e) => { e.preventDefault(); cell.classList.add('drag-over'); });
      cell.addEventListener('dragleave', () => cell.classList.remove('drag-over'));
      cell.addEventListener('drop', (e) => {
        e.preventDefault();
        cell.classList.remove('drag-over');
        this._onDropToInventory(i);
      });

      grid.appendChild(cell);
    }

    // Sell area
    const sellArea = this.el.querySelector('#inv-sell-area');
    if (sellArea) {
      sellArea.addEventListener('dragover', (e) => { e.preventDefault(); sellArea.classList.add('drag-over'); });
      sellArea.addEventListener('dragleave', () => sellArea.classList.remove('drag-over'));
      sellArea.addEventListener('drop', (e) => {
        e.preventDefault();
        sellArea.classList.remove('drag-over');
        this._onDropToSell();
      });
    }
  }

  // ─── Stats panel ──────────────────────────────────────────────────────────

  _renderStats() {
    const el = this.el.querySelector('#inv-stats-content');
    if (!el || !this._char) return;

    const char = this._char;
    const attrs = char.attributes ?? {};
    const derived = CharacterSystem.getDerivedAbilities(char);
    const equip = char.equipment ?? {};

    // Compute bonuses from equipment
    let defenseBonus = 0;
    let blockBonus = 0;
    let manaBonus = 0;
    let mightBonus = 0;
    let hpBonus = 0;

    for (const item of Object.values(equip)) {
      if (!item) continue;
      const stats = ItemSystem.getEffectiveStats(item);
      defenseBonus += stats.defense ?? 0;
      blockBonus   += stats.blockChance ?? 0;
      manaBonus    += stats.manaBonus ?? 0;
      mightBonus   += stats.mightBonus ?? 0;
      hpBonus      += stats.maxHPBonus ?? 0;

      // Attribute bonuses from affixes
      if (stats.attributeBonuses) {
        for (const [attr, val] of Object.entries(stats.attributeBonuses)) {
          if (attr in attrs) attrs[attr] = (attrs[attr] ?? 0) + val;
        }
      }
    }

    const maxHP   = (char.maxHP   ?? 0) + hpBonus;
    const maxMana = (char.maxMana ?? 0) + manaBonus;

    const rows = [
      { label: 'Class',     value: char.class ?? 'Adventurer' },
      { label: 'Level',     value: char.level ?? 1 },
      { label: 'HP',        value: `${char.hp ?? 0} / ${maxHP}`,   cls: (char.hp / maxHP) < 0.3 ? 'bad' : '' },
      { label: 'Mana',      value: `${char.mana ?? 0} / ${maxMana}` },
      { label: '',          value: '' }, // divider
      { label: 'Might',     value: attrs.might ?? 10 },
      { label: 'Agility',   value: attrs.agility ?? 10 },
      { label: 'Intellect', value: attrs.intellect ?? 10 },
      { label: 'Wisdom',    value: attrs.wisdom ?? 10 },
      { label: 'Endurance', value: attrs.endurance ?? 10 },
      { label: 'Presence',  value: attrs.presence ?? 10 },
      { label: '',          value: '' },
      { label: 'Defense',   value: defenseBonus },
      { label: 'Block',     value: blockBonus > 0 ? `${Math.round(blockBonus * 100)}%` : '0%' },
      { label: 'Athletics', value: derived.athletics ?? 0, cls: derived.athletics >= 5 ? 'good' : '' },
      { label: 'Perception',value: derived.perception ?? 0 },
      { label: 'Stealth',   value: derived.stealth ?? 0 },
      { label: 'Persuasion',value: derived.persuasion ?? 0 },
    ];

    el.innerHTML = '<div class="inv-stats-grid">' +
      rows.map(r => {
        if (!r.label) return '<div></div><div></div>';
        return `<div class="inv-stat-row" style="grid-column:1/-1">
          <span class="inv-stat-label">${r.label}</span>
          <span class="inv-stat-value ${r.cls ?? ''}">${r.value}</span>
        </div>`;
      }).join('') +
    '</div>';
  }

  // ─── Weight bar ───────────────────────────────────────────────────────────

  _renderWeight() {
    const char = this._char;
    if (!char) return;

    const might = char.attributes?.might ?? 10;
    let maxWeight = 10 + might * 3;

    // Belt bonus
    const beltItem = char.equipment?.belt;
    if (beltItem) {
      const beltStats = ItemSystem.getEffectiveStats(beltItem);
      maxWeight += beltStats.carryBonus ?? 0;
    }

    let currentWeight = 0;
    for (const item of (char.inventory ?? [])) {
      currentWeight += (item.weight ?? 0) * (item.quantity ?? 1);
    }

    const pct = Math.min(100, (currentWeight / maxWeight) * 100);
    const overweight = currentWeight > maxWeight;

    const fill = this.el.querySelector('#inv-weight-fill');
    const valueEl = this.el.querySelector('#inv-weight-value');

    if (fill) {
      fill.style.width = `${pct}%`;
      fill.classList.toggle('overweight', overweight);
    }
    if (valueEl) {
      valueEl.textContent = `${Math.round(currentWeight * 10) / 10} / ${Math.round(maxWeight * 10) / 10}`;
      valueEl.style.color = overweight ? '#c83020' : '';
    }
  }

  // ─── Tooltip ─────────────────────────────────────────────────────────────

  _showTooltip(instance, event, equippedSlot) {
    if (!this._tooltip) return;
    const base = ItemSystem.getBaseItem(instance.baseId);
    if (!base) return;

    const rarityColor = ItemSystem.getRarityColor(instance.rarity);
    const name = ItemSystem.getItemName(instance);
    const stats = instance.identified ? ItemSystem.getEffectiveStats(instance) : null;
    const { canEquip, warnings } = ItemSystem.canEquip(this._char, instance);

    let html = '';

    // Name
    if (!instance.identified) {
      html += `<div class="tt-name tt-unid">Unidentified ${base.name}</div>`;
    } else {
      html += `<div class="tt-name" style="color:${rarityColor}">${name}</div>`;
    }

    // Type line
    html += `<div class="tt-type">${base.type}${base.subtype ? ' — ' + base.subtype : ''}  |  Lvl ${instance.level ?? 1}</div>`;

    if (instance.identified && stats) {
      // Damage
      if (stats.damage) {
        html += `<div class="tt-stat">Damage: ${stats.damage.min}–${stats.damage.max}</div>`;
      }
      // Defense
      if (stats.defense > 0) html += `<div class="tt-stat">Defense: ${stats.defense}</div>`;
      // Block
      if (stats.blockChance > 0) html += `<div class="tt-stat">Block: ${Math.round(stats.blockChance * 100)}%</div>`;
      // Other numeric stats
      const statLabels = {
        manaBonus: 'Mana Bonus', mightBonus: 'Might Bonus',
        critBonus: 'Crit Chance', stunChance: 'Stun Chance',
        reach: 'Reach', moveSpeedBonus: 'Move Speed',
        carryBonus: 'Carry Bonus', spellPowerBonus: 'Spell Power',
        lightRadius: 'Light Radius', armorPen: 'Armor Pen',
      };
      for (const [key, label] of Object.entries(statLabels)) {
        const val = stats[key];
        if (val != null && val !== 0) {
          const pct = typeof val === 'number' && val < 1 && val > 0;
          html += `<div class="tt-stat">${label}: ${pct ? Math.round(val * 100) + '%' : val}</div>`;
        }
      }

      // Affix descriptions
      if (instance.affixes?.length > 0) {
        for (const affix of instance.affixes) {
          if (!affix.identified) continue;
          const desc = ItemSystem.getAffixDescription(affix.id);
          if (desc) html += `<div class="tt-affix">${desc}</div>`;
        }
      }

      // Comparison delta: if hovering an inventory item, compare with equipped
      if (!equippedSlot && base.slot && this._char.equipment?.[base.slot]) {
        const equipped = this._char.equipment[base.slot];
        if (equipped) {
          const eStats = ItemSystem.getEffectiveStats(equipped);
          const iStats = stats;
          html += `<div class="tt-delta">`;
          const compareKeys = ['defense', 'damage', 'manaBonus', 'critBonus', 'blockChance'];
          for (const key of compareKeys) {
            const iVal = typeof iStats[key] === 'object' ? ((iStats[key]?.min ?? 0) + (iStats[key]?.max ?? 0)) / 2 : (iStats[key] ?? 0);
            const eVal = typeof eStats[key] === 'object' ? ((eStats[key]?.min ?? 0) + (eStats[key]?.max ?? 0)) / 2 : (eStats[key] ?? 0);
            const diff = iVal - eVal;
            if (Math.abs(diff) > 0.001) {
              const sign = diff > 0 ? '+' : '';
              const cls = diff > 0 ? 'tt-delta-plus' : 'tt-delta-minus';
              const label = key.charAt(0).toUpperCase() + key.slice(1);
              html += `<div class="tt-delta-row"><span>${label}</span><span class="${cls}">${sign}${Math.round(diff * 100) / 100}</span></div>`;
            }
          }
          html += `</div>`;
        }
      }
    } else if (!instance.identified) {
      html += `<div class="tt-stat" style="color:#706050">Unidentified — use a Scroll of Identify</div>`;
    }

    // Consumable effect
    if (base.type === 'consumable' && base.effect) {
      const eff = base.effect;
      if (eff.restoreHP)   html += `<div class="tt-stat" style="color:#40a060">Restores ${eff.restoreHP} HP</div>`;
      if (eff.restoreMana) html += `<div class="tt-stat" style="color:#4090c0">Restores ${eff.restoreMana} Mana</div>`;
      if (eff.rationPoints)html += `<div class="tt-stat">+${eff.rationPoints} ration points</div>`;
      if (eff.removeStatus)html += `<div class="tt-stat">Removes: ${eff.removeStatus.join(', ')}</div>`;
      if (eff.identify)    html += `<div class="tt-stat" style="color:#7090c0">Identifies one item</div>`;
    }

    // Requirements warning
    if (warnings.length > 0) {
      html += warnings.map(w => `<div class="tt-req">${w}</div>`).join('');
    }

    // Description
    if (base.description) html += `<div class="tt-desc">${base.description}</div>`;

    // Action hint
    const isConsumable = base.type === 'consumable';
    const isEquippable = !!base.slot;
    if (equippedSlot) {
      html += `<div class="tt-action">Right-click or Shift+Click to unequip</div>`;
    } else if (isConsumable) {
      html += `<div class="tt-action">Right-click to use</div>`;
    } else if (isEquippable) {
      html += `<div class="tt-action">Click to equip</div>`;
    }

    this._tooltip.innerHTML = html;
    this._tooltip.classList.add('visible');
    this._moveTooltip(event);
  }

  _moveTooltip(event) {
    if (!this._tooltip?.classList.contains('visible')) return;
    const margin = 12;
    const tw = this._tooltip.offsetWidth;
    const th = this._tooltip.offsetHeight;
    let x = event.clientX + margin;
    let y = event.clientY + margin;
    if (x + tw > window.innerWidth - margin) x = event.clientX - tw - margin;
    if (y + th > window.innerHeight - margin) y = event.clientY - th - margin;
    this._tooltip.style.left = `${Math.max(margin, x)}px`;
    this._tooltip.style.top  = `${Math.max(margin, y)}px`;
  }

  _hideTooltip() {
    if (this._tooltip) this._tooltip.classList.remove('visible');
  }

  // ─── Item actions ─────────────────────────────────────────────────────────

  _onCellClick(item, index, event) {
    const base = ItemSystem.getBaseItem(item.baseId);
    if (!base) return;

    if (base.slot) {
      this._equipItem(item, index);
    }
    // non-equippable, non-consumable: do nothing on left-click
  }

  _onCellRightClick(item, index) {
    const base = ItemSystem.getBaseItem(item.baseId);
    if (!base) return;

    if (base.type === 'consumable') {
      this._useConsumable(item, index);
    } else if (base.slot) {
      // For equipped gear in inventory (shouldn't happen but just unequip from slot)
      // Find the slot and unequip
      for (const [slot, equipped] of Object.entries(this._char.equipment ?? {})) {
        if (equipped === item) {
          this._unequipItem(slot);
          return;
        }
      }
    }
  }

  _equipItem(item, inventoryIndex) {
    const base = ItemSystem.getBaseItem(item.baseId);
    if (!base?.slot) return;

    const { canEquip, warnings } = ItemSystem.canEquip(this._char, item);
    if (!canEquip) {
      DebugLog.warn(`[ui] Cannot equip ${item.name}: ${warnings.join(', ')}`);
      return;
    }

    let targetSlot = base.slot;

    // Ring: prefer empty ring1, then ring2
    if (base.slot === 'ring1') {
      const equip = this._char.equipment ?? {};
      if (!equip.ring1) targetSlot = 'ring1';
      else if (!equip.ring2) targetSlot = 'ring2';
      else targetSlot = 'ring1'; // replace ring1 by default
    }

    const inventory = this._char.inventory ?? [];
    const equip = this._char.equipment ?? {};

    // If something is already equipped in that slot, move it to inventory
    const currentEquipped = equip[targetSlot];
    if (currentEquipped) {
      inventory.push(currentEquipped);
    }

    // Remove from inventory
    inventory.splice(inventoryIndex, 1);

    // Equip
    equip[targetSlot] = item;
    this._char.equipment = equip;
    this._char.inventory = inventory;

    DebugLog.event(`[item] Equipped; name=${item.name} slot=${targetSlot} char=${this._char.name}`);
    this._renderAll();
  }

  _unequipItem(slotId) {
    const equip = this._char.equipment ?? {};
    const item = equip[slotId];
    if (!item) return;

    const inventory = this._char.inventory ?? [];
    inventory.push(item);
    equip[slotId] = null;
    this._char.equipment = equip;
    this._char.inventory = inventory;

    DebugLog.event(`[item] Unequipped; slot=${slotId} char=${this._char.name}`);
    this._renderAll();
  }

  _useConsumable(item, index) {
    const base = ItemSystem.getBaseItem(item.baseId);
    if (!base) return;

    // Scroll of identify: flag pending + wait for target click
    if (base.effect?.identify) {
      this._pendingIdentify = true;
      this._identifyScrollInstance = item;
      this._identifyScrollIndex = index;
      DebugLog.info('[ui] Awaiting identify target selection');
      return;
    }

    const { applied, message } = ItemSystem.useConsumable(item, this._char, {
      worldState: WorldState,
    });

    DebugLog.event(`[item] useConsumable result; applied=${applied} msg=${message}`);
    this._renderAll();
  }

  _resolveIdentify(targetItem) {
    if (!this._pendingIdentify) return;
    this._pendingIdentify = false;

    if (targetItem.identified) {
      DebugLog.info('[ui] Identify: target already identified');
      return;
    }

    const scrollItem = this._identifyScrollInstance;
    const { applied, message } = ItemSystem.useConsumable(scrollItem, this._char, {
      worldState: WorldState,
      targetItem,
    });

    DebugLog.event(`[item] identify result; applied=${applied} msg=${message}`);
    this._renderAll();
  }

  // ─── Drag and drop ────────────────────────────────────────────────────────

  _onDragStart(event, item, source) {
    this._dragItem = item;
    this._dragSource = source;
    event.dataTransfer.effectAllowed = 'move';
    event.dataTransfer.setData('text/plain', item.instanceId);
  }

  _onDragEnd() {
    this._dragItem = null;
    this._dragSource = null;
  }

  _onDropToSlot(slotId) {
    if (!this._dragItem) return;
    const base = ItemSystem.getBaseItem(this._dragItem.baseId);
    if (!base) return;

    const itemSlot = base.slot;
    let targetSlot = slotId;

    // Allow rings to swap between ring1/ring2
    if (itemSlot === 'ring1' && (slotId === 'ring1' || slotId === 'ring2')) {
      targetSlot = slotId;
    } else if (itemSlot !== targetSlot) {
      DebugLog.warn(`[ui] Drag drop: slot mismatch ${itemSlot} vs ${targetSlot}`);
      return;
    }

    const { canEquip, warnings } = ItemSystem.canEquip(this._char, this._dragItem);
    if (!canEquip) return;

    const equip = this._char.equipment ?? {};
    const inventory = this._char.inventory ?? [];

    // Remove from source
    if (this._dragSource === 'inventory') {
      const idx = inventory.indexOf(this._dragItem);
      if (idx !== -1) inventory.splice(idx, 1);
    } else {
      // Dragging from a different slot — clear that slot
      if (equip[this._dragSource] === this._dragItem) {
        equip[this._dragSource] = null;
      }
    }

    // Swap if slot occupied
    const current = equip[targetSlot];
    if (current && current !== this._dragItem) {
      if (this._dragSource === 'inventory') {
        inventory.push(current);
      } else {
        equip[this._dragSource] = current;
      }
    }

    equip[targetSlot] = this._dragItem;
    this._char.equipment = equip;
    this._char.inventory = inventory;

    DebugLog.event(`[item] Drag-equipped; name=${this._dragItem.name} slot=${targetSlot}`);
    this._renderAll();
  }

  _onDropToInventory(targetIndex) {
    if (!this._dragItem) return;

    const equip = this._char.equipment ?? {};
    const inventory = this._char.inventory ?? [];

    // Remove from source
    if (this._dragSource !== 'inventory') {
      if (equip[this._dragSource] === this._dragItem) {
        equip[this._dragSource] = null;
      }
    }

    const currentAtTarget = inventory[targetIndex];

    if (this._dragSource === 'inventory') {
      const srcIdx = inventory.indexOf(this._dragItem);
      if (srcIdx !== -1 && srcIdx !== targetIndex) {
        // Swap
        inventory[srcIdx] = currentAtTarget ?? inventory[srcIdx];
        inventory[targetIndex] = this._dragItem;
        if (!currentAtTarget) inventory.splice(srcIdx, 1);
      }
    } else {
      // From equipment slot to inventory cell
      if (currentAtTarget) {
        inventory.push(this._dragItem);
      } else {
        inventory.splice(targetIndex, 0, this._dragItem);
      }
    }

    this._char.equipment = equip;
    this._char.inventory = inventory;

    DebugLog.event(`[item] Drag-to-inventory; name=${this._dragItem.name}`);
    this._renderAll();
  }

  _onDropToSell() {
    if (!this._dragItem) return;
    const base = ItemSystem.getBaseItem(this._dragItem.baseId);
    if (!base) return;

    // Compute sell value: base price approximation
    const sellValue = Math.max(1, Math.floor((base.level ?? 1) * 3 * 0.3));
    WorldState.partyGold = (WorldState.partyGold ?? 0) + sellValue;

    // Remove from source
    const equip = this._char.equipment ?? {};
    const inventory = this._char.inventory ?? [];

    if (this._dragSource === 'inventory') {
      const idx = inventory.indexOf(this._dragItem);
      if (idx !== -1) inventory.splice(idx, 1);
    } else {
      if (equip[this._dragSource] === this._dragItem) {
        equip[this._dragSource] = null;
      }
    }

    this._char.equipment = equip;
    this._char.inventory = inventory;

    DebugLog.event(`[item] Sold; name=${this._dragItem.name} gold=${sellValue} totalGold=${WorldState.partyGold}`);
    this._renderAll();
  }

  // ─── Helpers ─────────────────────────────────────────────────────────────

  _shortName(name) {
    return name.length > 14 ? name.slice(0, 12) + '…' : name;
  }

  _getItemIcon(instance) {
    const base = ItemSystem.getBaseItem(instance.baseId);
    if (!base) return '?';

    const iconMap = {
      weapon:  { sword: '\u2694', axe: '\u2E32', dagger: '\uD83D\uDDE1', spear: '\uD83D\uDEA9', hammer: '\uD83D\uDD28', bow: '\uD83C\uDFF9', staff: '\uD83D\uDEB9', wand: '\u2728', default: '\u2694' },
      armor:   { leather: '\uD83E\uDDE5', robe: '\uD83D\uDC57', chainmail: '\u26D3', plate: '\uD83D\uDEE1', default: '\uD83E\uDDE5' },
      shield:  '\uD83D\uDEE1',
      accessory: { ring: '\uD83D\uDC8D', amulet: '\u2763', boots: '\uD83D\uDC62', gloves: '\uD83E\uDDE4', belt: '\u26AA', default: '\uD83D\uDCFF' },
      offhand: { quiver: '\uD83C\uDFF9', orb: '\uD83D\uDD2E', torch: '\uD83D\uDD6F', default: '\uD83D\uDEE1' },
      consumable: { potion: '\uD83E\uDDEA', scroll: '\uD83D\uDCDC', food: '\uD83C\uDF7D', tool: '\uD83D\uDD28', default: '\uD83E\uDDEA' },
      tool: '\uD83D\uDD27',
    };

    const typeMap = iconMap[base.type];
    if (!typeMap) return '\uD83D\uDCE6';
    if (typeof typeMap === 'string') return typeMap;
    return typeMap[base.subtype] ?? typeMap.default ?? '\uD83D\uDCE6';
  }

  // ─── Debug hooks ──────────────────────────────────────────────────────────

  _setupDebugHooks() {
    if (typeof window === 'undefined') return;

    window.__debugGetInventory = (nameOrId) => {
      let char = this._char;
      if (nameOrId) {
        char = CharacterSystem.getById(nameOrId)
          ?? CharacterSystem.getAll().find(c => c.name.toLowerCase() === String(nameOrId).toLowerCase())
          ?? this._char;
      }
      if (!char) return null;
      return {
        character: char.name,
        inventory: char.inventory ?? [],
        equipment: char.equipment ?? {},
        gold: WorldState.partyGold,
      };
    };
  }
}
